import{_ as a,H as t,f as l,i as s}from"./chunks/framework.nN4pLK1d.js";const p=JSON.parse('{"title":"Template","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/basic/template.md","filePath":"packages/rcml/email/concepts/basic/template.md"}'),c={name:"packages/rcml/email/concepts/basic/template.md"};function r(i,e,o,d,n,m){return t(),l("div",null,[...e[0]||(e[0]=[s(`<h1>Template</h1><p>An RCML template is a JSON tree with a fixed two-part structure: <code>rc-head</code> carries invisible metadata, and <code>rc-body</code> carries everything the recipient sees.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;rcml&gt;</span></span>
<span class="line"><span>  ├─ &lt;rc-head&gt;   — metadata: fonts, default styles, named classes, preview text, brand style</span></span>
<span class="line"><span>  └─ &lt;rc-body&gt;   — visible content: sections, columns, content elements</span></span></code></pre></div><p>The head/body split separates <em>brand appearance</em> from <em>message content</em>. <code>rc-head</code> holds everything that makes the email look like your brand — fonts, colour defaults, social links, logo. <code>rc-body</code> holds what the email says — the sections, images, text, and calls to action. Keeping them separate means you can update a brand colour without touching the content, or reuse the same template layout with a different visual identity.</p><h2 id="rc-head" tabindex="-1">rc-head <a class="header-anchor" href="#rc-head" aria-label="Permalink to &quot;rc-head&quot;">​</a></h2><p><code>rc-head</code> is not rendered into the email HTML. Its children configure the defaults and resources that <code>rc-body</code> elements draw on:</p><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-brand-style.html"><code>&lt;rc-brand-style&gt;</code></a> — references a saved brand-style preset by numeric ID</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-font.html"><code>&lt;rc-font&gt;</code></a> — registers a web font loaded from a URL</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-attributes.html"><code>&lt;rc-attributes&gt;</code></a> — sets default attribute values for body elements</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-preview.html"><code>&lt;rc-preview&gt;</code></a> — sets the inbox preview text shown before the email is opened</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-class.html"><code>&lt;rc-class&gt;</code></a> — defines a named reusable style class</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/head/rc-plain-text.html"><code>&lt;rc-plain-text&gt;</code></a> — provides the plain-text fallback version of the email</li></ul><p>The theme system writes directly into <code>rc-head</code>. Calling <code>applyTheme(doc, theme)</code> populates <code>rc-head</code> with default-attribute nodes and named classes, leaving <code>rc-body</code> untouched. This is why the split matters in practice — templates are built once and themed separately. See <a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/theme.html">Theme</a>.</p><h2 id="rc-body" tabindex="-1">rc-body <a class="header-anchor" href="#rc-body" aria-label="Permalink to &quot;rc-body&quot;">​</a></h2><p><code>rc-body</code> holds the visible email content, organised as a row-column grid. Sections contain columns, and columns contain content elements. See <a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/containers.html">Containers</a> for how the grid is structured and <a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/elements.html">Elements</a> for what goes inside the columns.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/containers.html">Containers</a></li><li><a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/elements.html">Elements</a></li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/">RCML Reference</a></li></ul>`,12)])])}const u=a(c,[["render",r]]);export{p as __pageData,u as default};
